function checkConnection(){fetch("/",{method:"HEAD"}).then(()=>{clearInterval(checkInterval),clearTimeout(connectionLostTimeout),window.location.href="/"}).catch(()=>{connectionLostTimeout&&clearTimeout(connectionLostTimeout),connectionLostTimeout=setTimeout(()=>{document.querySelector(".status-message").textContent="Device is restarting...",document.querySelector(".sub-message").textContent="Please wait for the device to complete the update"},1e4)})}let checkInterval,connectionLostTimeout;window.onload=function(){setTimeout(()=>{checkInterval=setInterval(checkConnection,2e3)},5e3)};